// src/backup/cards/DropboxCard.js
import React from 'react';
import { Cloud } from 'lucide-react';

export default function DropboxCard({ value, onEnter, onToggle }) {
  return (
    <div className="bg-white rounded-2xl shadow p-6 hover:shadow-md transition">
      <div className="flex items-center gap-3">
        <Cloud className="text-blue-500" />
        <h3 className="text-lg font-semibold">Dropbox</h3>
        <div className="ml-auto text-sm text-gray-500">
          {value?.enabled ? 'Habilitado' : 'Desabilitado'}
        </div>
      </div>

      <p className="text-sm text-gray-600 mt-2">
        Envie seus backups diretamente para uma pasta no Dropbox.
      </p>

      <div className="flex items-center gap-3 mt-4">
        <button
          onClick={onEnter}
          className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white px-4 py-2 rounded-full"
        >
          Configurar
        </button>

        <label className="flex items-center gap-2 text-sm">
          <input
            type="checkbox"
            checked={!!value?.enabled}
            onChange={(e) => onToggle(e.target.checked)}
          />
          Habilitar
        </label>
      </div>
    </div>
  );
}
